import React from 'react';

const Skills = () => {
  const skills = {
    'Core Languages': 'PHP, JavaScript, Basic Python',
    'Frameworks': 'Symfony, Zend, Laravel, Node.js, jQuery, Basic Django',
    'Platforms': 'Shopware 5 & 6, Odoo 17',
    'Frontend Technologies': 'HTML, Twig Template Engine, Smarty Template Engine, Embedded JavaScript templating, Basic React.js, Basic Vue.js, Basic CSS',
    'Databases': 'MySQL, Basic PostgreSQL',
    'Other Technologies': 'LAMP Stack, GIT, Ubuntu, AWS(EC2)',
  };

  return (
    // <section id="skills" className="skills-section py-5">
    //   <div className="container">
    //     <h2 className="text-center mb-4">Skills</h2>
    //     <div className="row block-separator">
    //       {Object.entries(skills).map(([category, skill], index) => (
    //         <div key={index} className="col-md-4 mb-3 skills-section-cls">
    //           <div className="card">
    //             <div className="card-body text-center">
    //               <p className="card-text"><strong>{category}</strong></p>
    //               <h5 className="card-title">{skill}</h5>
    //             </div>
    //           </div>
    //         </div>
    //       ))}
    //     </div>
    //   </div>
    // </section>

    <section id="skills" className="skills-section py-5">
      <div className="container">
        <h2 className="text-center mb-4">Skills</h2>
        <div class="block-separator skills-block">
          <div class="skills-content">
          {Object.entries(skills).map(([category, skill], index) => (
            <div key={index} className="col-md-4 mb-3 skills-section-cls">
            <p className="card-text"><strong>{category}</strong></p>
              <h5 className="card-title">{skill}</h5>
              </div>
          ))}
          </div>
        </div>
      </div>
    </section>
  );
};

export default Skills;
